  ('pukao-39f5e973-moex-00083', 'pukao-39f5e973', 'pukao-39f5e973-moex-113-156cbda0', 'sub-pukao-39f5e973-02', NULL, 'single_choice', '關於特權指令（privilegedinstruction）敘述，下列何者錯誤？', '["一般應用程式設計者所寫的程式可直接使用", "它們可能會對系統造成危害", "只能在核心模式（kernelmode）執行", "可用於管理中斷（interrupts）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:50+00:00", "source_pdf_sha1": "907ad3e14e9f", "answer_pdf_sha1": "780e4d7b0044", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "455", "s": "2707", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "計算機概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "資訊處理"}'::jsonb, NULL),
